import de.itemis.mps.editor.diagram.runtime.shape.AbstractShape;
import java.awt.Shape;
import java.awt.geom.Rectangle2D;
import java.awt.geom.GeneralPath;

public class PortShape extends AbstractShape {

  private boolean connected;
  private boolean left;

  public PortShape(boolean connected, boolean left) {
    this.connected = connected;
    this.left = left;
  }


  @Override
  public Shape getShape(final Rectangle2D bounds) {
    if (this.connected) {
      GeneralPath triangle = new GeneralPath();
      double width = bounds.getWidth();
      double height = bounds.getHeight();
      double x = bounds.getX();
      double y = bounds.getY();
      double x2 = x + width;
      double y2 = y + height;
      double centerY = y + height / 2;

      if (this.left) {
        triangle.moveTo(x2, y);
        triangle.lineTo(x, centerY);
        triangle.lineTo(x2, y2);
        triangle.closePath();
      } else {
        triangle.moveTo(x, y);
        triangle.lineTo(x2, centerY);
        triangle.lineTo(x, y2);
        triangle.closePath();
      }
      return triangle;
    } else {
      return bounds;
    }
  }



}
